scwin.sbm_retrievePayDecide_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        if ($c.gus.cfCheckCreateFlag() == true) {
            $c.gus.cfTurnCreateFlag(false);
        } else {
            if (ds_decide.getTotalRow() == 0) {
                await $c.win.alert(MSG_CM_WRN_002);
                $c.gus.cfDisableObjects([btn_cancel, btn_division, btn_reserve, btn_decide, btn_seizure, btn_delete, btn_batchjob]);
            } else {
                // 보류인경우 취소만 버튼 enable
                if (acb_payStsCd.getValue() == scwin.RESERVESTS || acb_payStsCd.getValue() == scwin.RESERVESTSLONG) { //보류, 장기보류
                    scwin.bRESERVE = true; 				//보류
                    scwin.bSEIZURE = false; 				//가압류						
                    scwin.bWAITSTS = false; 				//대기
                    scwin.bNONEVDMGNT = false; 			//무증빙
                    scwin.bCOLLMONEYWAIT = false;			//상계대기
                    scwin.bDECIDE = false;				//결정
                    $c.gus.cfEnableObjects([btn_cancel]);
                    $c.gus.cfDisableObjects([btn_division, btn_reserve, btn_decide, btn_seizure, btn_delete, btn_batchjob]);
                }   // 상계대기 인경우 분할,결정,보류,가압류,삭제만 버튼 enable
                else if (acb_payStsCd.getValue() == scwin.COLLMONEYWAIT) { //상계대기
                    scwin.bRESERVE = false;
                    scwin.bWAITSTS = true;
                    scwin.bCOLLMONEYWAIT = true;
                    scwin.bNONEVDMGNT = true;
                    scwin.bSEIZURE = false;
                    scwin.bDECIDE = true;
                    $c.gus.cfEnableObjects([btn_cancel, btn_decide]);
                    $c.gus.cfDisableObjects([btn_division, btn_reserve, btn_seizure, btn_delete, btn_batchjob]);
                    if (ds_delAdminSearch.getTotalRow <= 0) {
                        $c.gus.cfDisableObjects([btn_delete, btn_seizure]);
                    } else {
                        $c.gus.cfEnableObjects([btn_delete]);
                    }
                }

                // 무증빙 인경우 삭제만 버튼 enable
                else if (acb_payStsCd.getValue() == '26') {
                    scwin.bNONEVDMGNT = true;
                    scwin.bRESERVE = false;
                    scwin.bWAITSTS = true;
                    scwin.bCOLLMONEYWAIT = true;
                    scwin.bSEIZURE = false;
                    scwin.bDECIDE = true;
                    $c.gus.cfEnableObjects([btn_cancel, btn_decide]);
                    $c.gus.cfDisableObjects([btn_division, btn_reserve, btn_seizure, btn_delete]);
                    if (ds_delAdminSearch.getTotalRow() <= 0) {
                        $c.gus.cfDisableObjects([btn_delete, btn_seizure]);
                    } else {
                        $c.gus.cfEnableObjects([btn_delete]);
                    }
                }

                // 대기인경우 분할,결정,보류,가압류,삭제만 버튼 enable
                else if (acb_payStsCd.getValue() == scwin.WAITSTS) {
                    scwin.bRESERVE = false;
                    scwin.bWAITSTS = true;
                    scwin.bCOLLMONEYWAIT = true;
                    scwin.bSEIZURE = false;
                    scwin.bNONEVDMGNT = true;
                    scwin.bDECIDE = false;
                    $c.gus.cfEnableObjects([btn_division, btn_reserve, btn_decide, btn_batchjob]);
                    $c.gus.cfDisableObjects([btn_cancel]);
                    if (ds_delAdminSearch.getTotalRow() <= 0) {
                        $c.gus.cfDisableObjects([btn_delete, btn_seizure]);
                    } else {
                        $c.gus.cfEnableObjects([btn_delete, btn_seizure]);
                    }
                }
                // 결정인경우 취소만 버튼 enable
                else if (acb_payStsCd.getValue() == scwin.DECIDESTS) {
                    scwin.bRESERVE = false;
                    scwin.bWAITSTS = false;
                    scwin.bCOLLMONEYWAIT = false;
                    scwin.bSEIZURE = false;
                    scwin.bNONEVDMGNT = false;
                    scwin.bDECIDE = true;
                    $c.gus.cfEnableObjects([btn_cancel]);
                    $c.gus.cfDisableObjects([btn_division, btn_reserve, btn_decide, btn_delete, btn_seizure, btn_batchjob]);
                }
                // 가압류인경우 취소만 버튼 enable
                else if (acb_payStsCd.getValue() == scwin.SEIZURESTS) {
                    scwin.bRESERVE = false;
                    scwin.bWAITSTS = false;
                    scwin.bCOLLMONEYWAIT = false;
                    scwin.bDECIDE = false;
                    scwin.bNONEVDMGNT = false;
                    scwin.bSEIZURE = true
                    $c.gus.cfEnableObjects([btn_cancel]);
                    $c.gus.cfDisableObjects([btn_division, btn_reserve, btn_decide, btn_seizure, btn_delete, btn_batchjob]);
                } else {
                    $c.gus.cfDisableObjects([btn_cancel, btn_division, btn_reserve, btn_decide, btn_seizure, btn_delete, btn_batchjob]);
                }
            }
            ed_totalRow.setValue(ds_decide.getTotalRow());
            // $c.gus.cfShowTotalRows(totalRows,ds_decide.CountRow) ;
        }
        // gr_paymgnt.ColumnProp('selYn', 'HeadCheck') = "FALSE";
    }
};

scwin.sbm_savePayDecide_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        await $c.win.alert(MSG_CM_INF_001);
        scwin.f_Retrieve();
    }
};

scwin.sbm_mail_submitdone = async function (e) {
    if (e.responseJSON.resultDataSet[0].Msg != "FAIL") {
        await $c.win.alert(MSG_CM_INF_001);
    }
};

scwin.gr_paymgnt_oncellclick = async function (Row, columnIndex, Colid) {

    if (Colid == "outbrSlipNo") {
        $c.gus.cfShowSlipInfo(ds_decide.getCellData(Row, "outbrSlipNo"));
    }

    if (Colid == "selYn") {
        if (ds_decide.getCellData(Row, "selYn") == "1") {
            if (ds_decide.getCellData(Row, "payStsCd") == "33") {
                await $c.win.alert("택배이관된 건 입니다.");
                ds_decide.undoRow(Row);
                return false;
            }
            if (ds_decide.getCellData(Row, "status") == "Y") {
                ds_decide.undoRow(Row);
                return false;
            }
        }
    }
};

